import React, { useState } from 'react';
import Swal from 'sweetalert2';
import {
  Diamond,
  User,
  Mail,
  Lock,
  Eye,
  EyeOff,
  Building,
  Phone,
  MapPin,
  Globe
} from 'lucide-react';
import api from './services/api';

const HotelAdminRegister = ({ onSuccess, onBack }) => {
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    name: '',
    email: '',
    password: '',
    phone: '',
    hotelName: '',
    hotelAddress: '',
    hotelCity: '',
    hotelCountry: ''
  });

 const handleSubmit = async (e) => {
  e.preventDefault();
  setLoading(true);

  try {
    // Register via API with hotel info
    const response = await api.post('/auth/register', {
      name: form.name,
      email: form.email,
      password: form.password,
      phone: form.phone,
      role: 'hotel_admin',
      hotelName: form.hotelName,
      hotelAddress: form.hotelAddress,
      hotelCity: form.hotelCity,
      hotelCountry: form.hotelCountry
    });

    if (response.data.success) {
      // Also save to localStorage for immediate visibility
      const newPartner = {
        id: response.data.data._id,
        name: form.name,
        email: form.email,
        phone: form.phone,
        hotelName: form.hotelName,
        hotelAddress: form.hotelAddress,
        hotelCity: form.hotelCity,
        hotelCountry: form.hotelCountry,
        role: 'hotel_admin',
        status: 'pending',
        appliedAt: new Date().toISOString(),
        userId: response.data.data._id
      };

      const existing = JSON.parse(localStorage.getItem('pendingPartners')) || [];
      localStorage.setItem('pendingPartners', JSON.stringify([...existing, newPartner]));

      Swal.fire({
        icon: 'success',
        title: 'Submitted!',
        text: 'Your application is pending system admin approval. You will receive an email once approved.',
        confirmButtonColor: '#06b6d4'
      });

      onSuccess();
    }
  } catch (error) {
    Swal.fire({
      icon: 'error',
      title: 'Registration Failed',
      text: error.response?.data?.error || 'Something went wrong',
      confirmButtonColor: '#ef4444'
    });
  } finally {
    setLoading(false);
  }
};

  const updateForm = (field, value) => {
    setForm(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 relative overflow-hidden">
      {/* Background */}
      <div className="absolute inset-0">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/20 rounded-full blur-3xl" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-cyan-600/20 rounded-full blur-3xl" />
      </div>

      <div className="relative z-10 w-full max-w-lg">
        {/* Logo */}
        <div className="flex justify-center mb-8">
          <div className="flex items-center gap-2">
            <Diamond className="w-10 h-10 text-cyan-400" />
            <span className="text-3xl font-bold bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">
              AI STAY
            </span>
          </div>
        </div>

        {/* Card */}
        <div className="bg-white/5 backdrop-blur-xl rounded-3xl p-8 border border-white/10">
          <h2 className="text-2xl font-bold text-center text-white mb-2">
            Become a Partner
          </h2>
          <p className="text-gray-400 text-center mb-8">
            Register your hotel and get approved by our system admin
          </p>

          <form onSubmit={handleSubmit} className="space-y-5">
            {/* PERSONAL INFO */}
            <div className="space-y-4">
              <h3 className="text-sm font-semibold text-cyan-400 uppercase tracking-wider">Personal Information</h3>

              <div>
                <label className="text-sm text-gray-300">Full Name *</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    placeholder="Enter your full name"
                    className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('name', e.target.value)}
                    required
                  />
                </div>
              </div>

              <div>
                <label className="text-sm text-gray-300">Email *</label>
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    type="email"
                    placeholder="Enter your email"
                    className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('email', e.target.value)}
                    required
                  />
                </div>
              </div>

              <div>
                <label className="text-sm text-gray-300">Phone</label>
                <div className="relative">
                  <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    type="tel"
                    placeholder="+63..."
                    className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('phone', e.target.value)}
                  />
                </div>
              </div>

              <div>
                <label className="text-sm text-gray-300">Password *</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    type={showPassword ? 'text' : 'password'}
                    placeholder="Enter password (min 6 characters)"
                    className="w-full pl-12 pr-14 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('password', e.target.value)}
                    minLength="6"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(prev => !prev)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-cyan-400 z-10"
                  >
                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                  </button>
                </div>
              </div>
            </div>

            {/* HOTEL INFO */}
            <div className="space-y-4 pt-4 border-t border-white/10">
              <h3 className="text-sm font-semibold text-purple-400 uppercase tracking-wider">Hotel Information</h3>

              <div>
                <label className="text-sm text-gray-300">Hotel Name *</label>
                <div className="relative">
                  <Building className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    placeholder="Enter hotel name"
                    className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('hotelName', e.target.value)}
                    required
                  />
                </div>
              </div>

              <div>
                <label className="text-sm text-gray-300">Hotel Address</label>
                <div className="relative">
                  <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    placeholder="Street address"
                    className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('hotelAddress', e.target.value)}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-sm text-gray-300">City</label>
                  <input
                    placeholder="City"
                    className="w-full px-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                    onChange={(e) => updateForm('hotelCity', e.target.value)}
                  />
                </div>
                <div>
                  <label className="text-sm text-gray-300">Country</label>
                  <div className="relative">
                    <Globe className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                    <input
                      placeholder="Country"
                      className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white placeholder-gray-500 focus:border-cyan-500/50 focus:outline-none"
                      onChange={(e) => updateForm('hotelCountry', e.target.value)}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* SUBMIT */}
            <button
              type="submit"
              disabled={loading}
              className="w-full py-4 bg-gradient-to-r from-cyan-500 via-purple-500 to-pink-500 rounded-xl font-bold text-white hover:shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? (
                <span className="flex items-center justify-center gap-2">
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  Submitting...
                </span>
              ) : (
                'Submit Application'
              )}
            </button>
          </form>

          {/* BACK BUTTON */}
          <button
            onClick={() => {
              if (onBack) {
                onBack();
              } else {
                window.location.reload();
              }
            }}
            className="w-full mt-4 text-gray-400 hover:text-cyan-400 text-sm transition-colors"
          >
            ← Back to Home
          </button>
        </div>
      </div>
    </div>
  );
};

export default HotelAdminRegister;
